import{_ as i,o as e,c as s,ag as t}from"./chunks/framework.DHfb4PWj.js";const p=JSON.parse('{"title":"React Fiber 架构与 Diff 算法深度解析","description":"","frontmatter":{},"headers":[],"relativePath":"interview/React/fiber-diff.md","filePath":"interview/React/fiber-diff.md"}'),l={name:"interview/React/fiber-diff.md"};function a(o,d,f,r,c,v){return e(),s("div",null,[...d[0]||(d[0]=[t('<h1 id="react-fiber-架构与-diff-算法深度解析" tabindex="-1">React Fiber 架构与 Diff 算法深度解析 <a class="header-anchor" href="#react-fiber-架构与-diff-算法深度解析" aria-label="Permalink to &quot;React Fiber 架构与 Diff 算法深度解析&quot;">​</a></h1><blockquote><p>本文围绕 <strong>&quot;Fiber 是什么 → 双缓冲机制 → 协调流程 → Diff 策略&quot;</strong> 这条主线，配合可视化图解，帮你建立对 React 内部调和过程的完整认知。</p></blockquote><hr><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><ul><li><a href="#一什么是-fiber核心字段拆解">一、什么是 Fiber？核心字段拆解</a></li><li><a href="#二双缓冲树机制">二、双缓冲树机制</a></li><li><a href="#三协调流程总览beginwork--completework">三、协调流程总览：beginWork → completeWork</a></li><li><a href="#四单节点-diff--reconcilesingleelement">四、单节点 Diff —— reconcileSingleElement</a></li><li><a href="#五多节点-diff--reconcilechildrenarray-两轮遍历">五、多节点 Diff —— reconcileChildrenArray 两轮遍历</a></li><li><a href="#六key-的本质作用">六、key 的本质作用</a></li><li><a href="#七首次挂载-vs-更新对比总结">七、首次挂载 vs 更新对比总结</a></li></ul><hr><hr><h2 id="一、什么是-fiber-核心字段拆解" tabindex="-1">一、什么是 Fiber？核心字段拆解 <a class="header-anchor" href="#一、什么是-fiber-核心字段拆解" aria-label="Permalink to &quot;一、什么是 Fiber？核心字段拆解&quot;">​</a></h2><p><strong>Fiber</strong> 是 React 16 重写内核后引入的核心数据结构，本质是一个 <strong>JavaScript 对象</strong>。每个 React 组件（或 DOM 节点）都对应一个 Fiber 节点，它在整个组件的生命周期内<strong>持久存在</strong>，是 React 协调引擎真正操作的对象。</p><blockquote><p>⚠️ <strong>注意</strong>：React Element 每次渲染都会重新生成，但 Fiber 节点不会——它被复用并持续更新。</p></blockquote><div class="fd"><div class="fd-card"><div class="fd-title">📊 图解一：Fiber 节点核心字段</div><div class="fd-fields"><div class="fd-field fd-f-id"><div class="fd-field-tag">🏷️ 身份标识</div><div class="fd-field-name">type</div><div class="fd-field-desc">组件函数本身（函数组件）或字符串 <code>&#39;div&#39;</code>（宿主节点）。这是 Diff 的关键依据之一。</div></div><div class="fd-field fd-f-id"><div class="fd-field-tag">🏷️ 身份标识</div><div class="fd-field-name">key</div><div class="fd-field-desc">用户显式设置的唯一标识，优先于 type 进行列表项匹配。</div></div><div class="fd-field fd-f-id"><div class="fd-field-tag">🏷️ 身份标识</div><div class="fd-field-name">tag</div><div class="fd-field-desc">Fiber 类型枚举，区分函数组件（0）、类组件（1）、HostComponent（5，即原生 DOM 节点）等。</div></div><div class="fd-field fd-f-st"><div class="fd-field-tag">📦 状态 / 数据</div><div class="fd-field-name">pendingProps</div><div class="fd-field-desc">本次渲染即将使用的新 props，由父组件传入或 React Element 提供。</div></div><div class="fd-field fd-f-st"><div class="fd-field-tag">📦 状态 / 数据</div><div class="fd-field-name">memoizedState</div><div class="fd-field-desc">函数组件的 Hook 链表头节点；或类组件的 <code>this.state</code>。上次渲染后的已确认状态。</div></div><div class="fd-field fd-f-st"><div class="fd-field-tag">📦 状态 / 数据</div><div class="fd-field-name">memoizedProps</div><div class="fd-field-desc">上次渲染后已确认的 props，用于本次与 pendingProps 对比。</div></div><div class="fd-field fd-f-ef"><div class="fd-field-tag">⚡ 副作用</div><div class="fd-field-name">flags (effectTag)</div><div class="fd-field-desc">标记本节点需要在 Commit 阶段进行什么 DOM 操作：Placement（插入）、Update（更新）、Deletion（删除）。</div></div><div class="fd-field fd-f-ef"><div class="fd-field-tag">⚡ 副作用</div><div class="fd-field-name">updateQueue</div><div class="fd-field-desc">待处理的状态更新队列，<code>setState</code> 产生的 Update 对象会挂载在这里等待处理。</div></div><div class="fd-field fd-f-tr"><div class="fd-field-tag">🌳 树形结构</div><div class="fd-field-name">return</div><div class="fd-field-desc">指向父 Fiber 节点（注意：不是 <code>parent</code>，React 历史命名习惯）。</div></div><div class="fd-field fd-f-tr"><div class="fd-field-tag">🌳 树形结构</div><div class="fd-field-name">child</div><div class="fd-field-desc">指向第一个子 Fiber 节点。</div></div><div class="fd-field fd-f-tr"><div class="fd-field-tag">🌳 树形结构</div><div class="fd-field-name">sibling</div><div class="fd-field-desc">指向下一个兄弟 Fiber 节点。通过 <code>child → sibling → sibling</code> 链表表达多个子节点。</div></div><div class="fd-field fd-f-sc"><div class="fd-field-tag">🔄 双缓冲</div><div class="fd-field-name">alternate</div><div class="fd-field-desc">指向另一棵树中对应的 Fiber 节点（current ↔ workInProgress 互相引用）。</div></div><div class="fd-field fd-f-sc"><div class="fd-field-tag">🔄 双缓冲</div><div class="fd-field-name">stateNode</div><div class="fd-field-desc">类组件实例（<code>this</code>）、函数组件为 <code>null</code>、DOM 节点为真实 DOM 引用。</div></div></div><div class="fd-note fd-nb" style="margin-top:14px;">💡 Fiber 节点通过 <code>return / child / sibling</code> 三个指针把整棵组件树表示成一个<strong>单链表</strong>，这让 React 可以随时中断遍历，并在之后恢复——这是并发模式（Concurrent Mode）可中断渲染的基础。</div></div></div><hr><h2 id="二、双缓冲树机制" tabindex="-1">二、双缓冲树机制 <a class="header-anchor" href="#二、双缓冲树机制" aria-label="Permalink to &quot;二、双缓冲树机制&quot;">​</a></h2><p>React 内部始终维护<strong>两棵 Fiber 树</strong>：</p><ul><li><strong>current 树</strong>：当前屏幕上正在显示的内容所对应的 Fiber 树，<code>FiberRoot.current</code> 指向它的根节点。</li><li><strong>workInProgress（WIP）树</strong>：正在构建中的、描述&quot;下一帧&quot;内容的 Fiber 树。</li></ul><p>当一次更新完成、WIP 树被 Commit 到 DOM 后，<code>FiberRoot.current</code> 会切换指向 WIP 树，原来的 current 树则成为下一次更新的&quot;旧树&quot;。这种&quot;乒乓切换&quot;的设计就叫做<strong>双缓冲（Double Buffering）</strong>。</p><div class="fd"><div class="fd-card"><div class="fd-title">📊 图解二：双缓冲树 —— 两棵树如何配合工作</div><div class="fd-tree-wrap" style="align-items:stretch;"><div class="fd-tree-col"><div class="fd-tree-hd fd-tree-hd-c">current 树（屏幕上正在显示）</div><div class="fd-tree" style="font-size:11px;line-height:1.8;"><div><span class="fd-nd fd-nd-c">FiberRoot</span></div><div style="padding-left:16px;">└─ <span class="fd-nd fd-nd-c">App</span></div><div style="padding-left:32px;">├─ <span class="fd-nd fd-nd-c">Header</span></div><div style="padding-left:32px;">└─ <span class="fd-nd fd-nd-c">Content</span></div><div style="padding-left:48px;">└─ <span class="fd-nd fd-nd-c">List</span></div></div><div class="fd-note fd-ng" style="margin-top:10px;font-size:11px;">✅ 用户当前看到的 UI<br>每个节点存储着当前的 state/props/DOM 引用</div></div><div class="fd-arr-mid" style="flex-direction:column;gap:6px;font-size:11px;color:#555;"><div style="text-align:center;font-size:20px;">⇄</div><div style="font-size:10px;text-align:center;">alternate<br>互指</div></div><div class="fd-tree-col"><div class="fd-tree-hd fd-tree-hd-w">workInProgress 树（正在构建）</div><div class="fd-tree" style="font-size:11px;line-height:1.8;"><div><span class="fd-nd fd-nd-w">FiberRoot</span></div><div style="padding-left:16px;">└─ <span class="fd-nd fd-nd-w">App</span></div><div style="padding-left:32px;">├─ <span class="fd-nd fd-nd-w">Header</span></div><div style="padding-left:32px;">└─ <span class="fd-nd fd-nd-w">Content</span></div><div style="padding-left:48px;">└─ <span class="fd-nd fd-nd-w">List</span> 🔄 <span style="font-size:10px;color:#7eb3ff;">新 props</span></div></div><div class="fd-note fd-nb" style="margin-top:10px;font-size:11px;">⚙️ Render 阶段正在构建<br>尽量复用 current 节点（通过 createWorkInProgress）</div></div></div><div style="margin-top:14px;padding:12px 14px;background:#1e1b2e;border-radius:8px;border:1px solid #2e3347;"><div style="font-size:11px;font-weight:700;color:#d4a8ff;margin-bottom:8px;">🔄 Commit 完成后：指针切换</div><div class="fd-flow" style="flex-wrap:nowrap;align-items:center;gap:8px;font-size:11px;"><span class="fd-fbox fd-fbox-p" style="min-width:0;padding:5px 10px;">WIP 树构建完成</span><span class="fd-farr">→</span><span class="fd-fbox fd-fbox-g" style="min-width:0;padding:5px 10px;">Commit 写入 DOM</span><span class="fd-farr">→</span><span class="fd-fbox fd-fbox-y" style="min-width:0;padding:5px 10px;">FiberRoot.current = WIP</span><span class="fd-farr">→</span><span class="fd-fbox fd-fbox-b" style="min-width:0;padding:5px 10px;">原 current 变成下次的&quot;旧树&quot;</span></div></div><div class="fd-note fd-ny" style="margin-top:10px;">⚠️ <strong>为什么这样设计？</strong> 双缓冲确保了&quot;在建&quot;和&quot;在用&quot;互不干扰，即使 Render 阶段被中断重来（并发模式），当前屏幕也不受影响；Commit 阶段只需一次原子性切换，避免用户看到中间状态。</div></div></div><hr><h2 id="三、协调流程总览-beginwork-→-completework" tabindex="-1">三、协调流程总览：beginWork → completeWork <a class="header-anchor" href="#三、协调流程总览-beginwork-→-completework" aria-label="Permalink to &quot;三、协调流程总览：beginWork → completeWork&quot;">​</a></h2><p>React 的协调（Reconciliation）过程由 <code>workLoopSync</code>（同步）或 <code>workLoopConcurrent</code>（并发）驱动，本质是对 Fiber 树进行<strong>深度优先遍历</strong>，分两个阶段处理每个节点：</p><div class="fd"><div class="fd-card"><div class="fd-title">📊 图解三：协调整体流程（深度优先遍历）</div><div style="display:flex;gap:14px;flex-wrap:wrap;"><div style="flex:1;min-width:260px;"><div style="font-size:11px;font-weight:700;color:#7eb3ff;margin-bottom:8px;padding:5px 10px;background:rgba(79,142,247,.1);border-radius:6px;">⬇️ 向下：beginWork（入）</div><div class="fd-steps"><div class="fd-step"><div class="fd-step-num fd-step-b">1</div><div class="fd-step-body"><div class="fd-step-title" style="color:#7eb3ff;">接收当前 Fiber 节点</div><div class="fd-step-desc">根据 <code>fiber.tag</code> 判断类型（函数组件、类组件、HostComponent 等）</div></div></div><div class="fd-step"><div class="fd-step-num fd-step-b">2</div><div class="fd-step-body"><div class="fd-step-title" style="color:#7eb3ff;">执行组件函数 / render</div><div class="fd-step-desc">函数组件：调用函数体，执行 Hooks；类组件：调用 <code>render()</code>；宿主节点：直接处理 props</div></div></div><div class="fd-step"><div class="fd-step-num fd-step-b">3</div><div class="fd-step-body"><div class="fd-step-title" style="color:#7eb3ff;">reconcileChildren（Diff）</div><div class="fd-step-desc">拿到返回的 React Element，与旧的子 Fiber 做对比，生成新的子 Fiber 链表，挂到 <code>workInProgress.child</code></div></div></div><div class="fd-step"><div class="fd-step-num fd-step-b">4</div><div class="fd-step-body"><div class="fd-step-title" style="color:#7eb3ff;">返回第一个子节点</div><div class="fd-step-desc">工作循环继续向下处理子节点，直到叶子节点（<code>child === null</code>）</div></div></div></div></div><div style="flex:1;min-width:260px;"><div style="font-size:11px;font-weight:700;color:#6ef5a8;margin-bottom:8px;padding:5px 10px;background:rgba(61,220,132,.08);border-radius:6px;">⬆️ 向上：completeWork（出）</div><div class="fd-steps"><div class="fd-step"><div class="fd-step-num fd-step-g">1</div><div class="fd-step-body"><div class="fd-step-title" style="color:#6ef5a8;">到达叶子节点后触发</div><div class="fd-step-desc">当 <code>beginWork</code> 返回 <code>null</code>（无子节点），开始回溯</div></div></div><div class="fd-step"><div class="fd-step-num fd-step-g">2</div><div class="fd-step-body"><div class="fd-step-title" style="color:#6ef5a8;">处理宿主节点的 DOM 操作</div><div class="fd-step-desc">对于 <code>HostComponent</code>：首次创建 DOM 实例，或标记属性变更（写入 <code>flags</code>）</div></div></div><div class="fd-step"><div class="fd-step-num fd-step-g">3</div><div class="fd-step-body"><div class="fd-step-title" style="color:#6ef5a8;">收集副作用（effectList）</div><div class="fd-step-desc">将有 <code>flags</code> 标记的节点收集到父节点的副作用链表，向上冒泡</div></div></div><div class="fd-step"><div class="fd-step-num fd-step-g">4</div><div class="fd-step-body"><div class="fd-step-title" style="color:#6ef5a8;">转向兄弟节点或继续回溯</div><div class="fd-step-desc">有 <code>sibling</code> → 对兄弟节点继续 beginWork；否则向 <code>return</code>（父节点）回溯</div></div></div></div></div></div><div style="margin-top:14px;padding:12px 16px;background:#191c2a;border-radius:8px;border:1px solid #2e3347;font-size:11px;"><div style="color:#a8b0cc;font-weight:700;margin-bottom:6px;">遍历顺序示例（App → A → A1 → A2 → B）：</div><div style="font-family:monospace;line-height:2;color:#8b90a8;"><span style="color:#7eb3ff;">beginWork</span>(App) → <span style="color:#7eb3ff;">beginWork</span>(A) → <span style="color:#7eb3ff;">beginWork</span>(A1) → <span style="color:#6ef5a8;">completeWork</span>(A1) → <span style="color:#7eb3ff;">beginWork</span>(A2) → <span style="color:#6ef5a8;">completeWork</span>(A2) → <span style="color:#6ef5a8;">completeWork</span>(A) → <span style="color:#7eb3ff;">beginWork</span>(B) → <span style="color:#6ef5a8;">completeWork</span>(B) → <span style="color:#6ef5a8;">completeWork</span>(App) </div></div><div class="fd-note fd-nb" style="margin-top:10px;">💡 <code>beginWork</code> 阶段完成的是&quot;判断与标记&quot;，<code>completeWork</code> 完成的是&quot;收集与准备&quot;。整个 Render 阶段结束后，所有需要做的 DOM 操作都已被收集，Commit 阶段按清单执行即可。</div></div></div><hr><h2 id="四、单节点-diff-——-reconcilesingleelement" tabindex="-1">四、单节点 Diff —— reconcileSingleElement <a class="header-anchor" href="#四、单节点-diff-——-reconcilesingleelement" aria-label="Permalink to &quot;四、单节点 Diff —— reconcileSingleElement&quot;">​</a></h2><p>当组件的 <code>render</code> 返回<strong>单个 React Element</strong>（非数组）时，React 调用 <code>reconcileSingleElement</code>。</p><p><strong>核心逻辑</strong>：在旧的子 Fiber 链表中寻找能被<strong>复用</strong>的节点，判断条件依次为 <code>key</code> 和 <code>type</code>。</p><div class="fd"><div class="fd-card"><div class="fd-title">📊 图解四：单节点 Diff 决策流程</div><div class="fd-flow" style="flex-wrap:wrap;gap:8px;align-items:center;"><div class="fd-fbox fd-fbox-b" style="text-align:left;padding:10px 14px;min-width:130px;"> 新 React Element<br><span style="font-size:10px;color:#555;font-weight:400;">（render 返回值）</span></div><div class="fd-farr">→</div><div class="fd-fbox fd-fbox-p" style="padding:10px 14px;">遍历旧子 Fiber 链表</div><div class="fd-farr">→</div><div class="fd-fbox-dec">key<br>相同？</div></div><div style="display:flex;gap:12px;margin-top:10px;flex-wrap:wrap;"><div style="flex:1;min-width:220px;border-radius:9px;border:1px solid #2e3347;padding:13px;background:#1a1e2a;"><div style="font-size:11px;font-weight:700;color:#ff8f8f;margin-bottom:10px;">❌ key 不同</div><div class="fd-steps"><div class="fd-step" style="border-bottom:none;padding:4px 0;"><div class="fd-step-num fd-step-r" style="width:20px;height:20px;font-size:10px;">1</div><div class="fd-step-body"><div class="fd-step-desc">将该旧 Fiber 标记为 <strong>Deletion</strong>（删除）</div></div></div><div class="fd-step" style="border-bottom:none;padding:4px 0;"><div class="fd-step-num fd-step-r" style="width:20px;height:20px;font-size:10px;">2</div><div class="fd-step-body"><div class="fd-step-desc">继续遍历链表中的下一个兄弟节点，重复比较</div></div></div><div class="fd-step" style="border-bottom:none;padding:4px 0;"><div class="fd-step-num fd-step-r" style="width:20px;height:20px;font-size:10px;">3</div><div class="fd-step-body"><div class="fd-step-desc">全部遍历后仍无匹配 → 调用 <code>createFiberFromElement</code> 全新创建</div></div></div></div></div><div style="flex:1;min-width:220px;border-radius:9px;border:1px solid #2e3347;padding:13px;background:#1a2418;"><div style="font-size:11px;font-weight:700;color:#6ef5a8;margin-bottom:10px;">✅ key 相同，再判断 type</div><div class="fd-steps"><div class="fd-step" style="padding:6px 0;"><div class="fd-step-num fd-step-g" style="width:20px;height:20px;font-size:10px;">A</div><div class="fd-step-body"><div class="fd-step-desc"><strong>type 也相同</strong>：调用 <code>useFiber</code>（createWorkInProgress）<br>克隆旧 Fiber，更新 pendingProps → <span style="color:#6ef5a8;">节点复用</span></div></div></div><div class="fd-step" style="border-bottom:none;padding:6px 0;"><div class="fd-step-num fd-step-r" style="width:20px;height:20px;font-size:10px;">B</div><div class="fd-step-body"><div class="fd-step-desc"><strong>type 不同</strong>：key 相同说明是同一&quot;位置&quot;的节点，但类型变了<br>→ 删除旧 Fiber 及其所有兄弟，<code>createFiberFromElement</code> 全新创建</div></div></div></div></div></div><div style="margin-top:12px;padding:11px 14px;background:#191c2a;border-radius:8px;border:1px solid #2e3347;font-size:11px;"><div style="color:#a8b0cc;font-weight:700;margin-bottom:8px;">💬 用一个例子理解&quot;复用 vs 新建&quot;的代价</div><div style="display:flex;gap:10px;flex-wrap:wrap;"><div style="flex:1;min-width:160px;padding:8px 11px;border-radius:7px;background:rgba(61,220,132,.07);border:1px solid rgba(61,220,132,.2);"><div style="color:#6ef5a8;font-weight:700;font-size:11px;margin-bottom:4px;">复用节点 ✅</div><div style="color:#8b90a8;font-size:11px;">仅更新 pendingProps<br>保留组件状态（state/ref）<br>仅 DOM 属性变更</div></div><div style="flex:1;min-width:160px;padding:8px 11px;border-radius:7px;background:rgba(255,92,92,.07);border:1px solid rgba(255,92,92,.2);"><div style="color:#ff8f8f;font-weight:700;font-size:11px;margin-bottom:4px;">新建节点 ❌</div><div style="color:#8b90a8;font-size:11px;">全部重建，状态丢失<br>需要 DOM 插入（mount）<br>会触发 unmount 生命周期</div></div></div></div><div class="fd-note fd-nr" style="margin-top:10px;">⚠️ <strong>关键结论</strong>：判断条件是 <strong>key 优先，type 其次</strong>。key 不同时，React 不会再判断 type——直接认为这不是同一个节点。这就是为什么 key 写错会导致组件状态意外丢失。</div></div></div><hr><h2 id="五、多节点-diff-——-reconcilechildrenarray-两轮遍历" tabindex="-1">五、多节点 Diff —— reconcileChildrenArray 两轮遍历 <a class="header-anchor" href="#五、多节点-diff-——-reconcilechildrenarray-两轮遍历" aria-label="Permalink to &quot;五、多节点 Diff —— reconcileChildrenArray 两轮遍历&quot;">​</a></h2><p>当 <code>render</code> 返回的是<strong>数组</strong>（多个子节点）时，React 使用 <code>reconcileChildrenArray</code>，通过<strong>两轮遍历</strong>处理新旧节点列表。</p><blockquote><p>💡 React 的列表 Diff <strong>不使用传统的最长公共子序列（LCS）算法</strong>，而是针对&quot;大多数更新是顺序不变的小变动&quot;这一实际场景，做了贪心优化。</p></blockquote><div class="fd"><div class="fd-card"><div class="fd-title">📊 图解五：多节点 Diff —— 两轮遍历详解</div><div style="display:flex;gap:12px;flex-wrap:wrap;margin-bottom:12px;"><div style="flex:1;min-width:300px;"><div style="font-size:11px;font-weight:700;color:#7eb3ff;padding:5px 10px;background:rgba(79,142,247,.1);border-radius:6px;margin-bottom:8px;">🔁 第一轮：顺序遍历，处理可预测的变化</div><div class="fd-steps"><div class="fd-step"><div class="fd-step-num fd-step-b">1</div><div class="fd-step-body"><div class="fd-step-title" style="color:#7eb3ff;">同时从头开始遍历新旧两个列表</div><div class="fd-step-desc">按索引位置逐个比较 <code>newChildren[i]</code> 与旧 Fiber 链表中对应位置的节点</div></div></div><div class="fd-step"><div class="fd-step-num fd-step-b">2</div><div class="fd-step-body"><div class="fd-step-title" style="color:#7eb3ff;">key 和 type 都相同 → 复用，继续</div><div class="fd-step-desc">调用 <code>updateSlot</code>，复用并更新 props，指针前进</div></div></div><div class="fd-step" style="border-bottom:none;"><div class="fd-step-num fd-step-r">3</div><div class="fd-step-body"><div class="fd-step-title" style="color:#ff8f8f;">key 不匹配 → 立即退出第一轮</div><div class="fd-step-desc">任意一侧 key 不一致，第一轮终止，进入第二轮处理剩余节点</div></div></div></div></div><div style="flex:1;min-width:300px;"><div style="font-size:11px;font-weight:700;color:#ffe599;padding:5px 10px;background:rgba(255,209,102,.08);border-radius:6px;margin-bottom:8px;">🔁 第二轮：处理移动、新增、删除</div><div class="fd-steps"><div class="fd-step"><div class="fd-step-num fd-step-y">1</div><div class="fd-step-body"><div class="fd-step-title" style="color:#ffe599;">把旧链表剩余节点存入 Map</div><div class="fd-step-desc">以 <code>key → Fiber</code> 或 <code>index → Fiber</code> 为索引，快速查找可复用节点（O(1)）</div></div></div><div class="fd-step"><div class="fd-step-num fd-step-y">2</div><div class="fd-step-body"><div class="fd-step-title" style="color:#ffe599;">遍历新列表剩余项</div><div class="fd-step-desc">在 Map 中查找对应 key：<br>✅ 找到且 type 相同 → 复用，从 Map 移除<br>❌ 未找到 → 新建 Fiber（Placement 标记）</div></div></div><div class="fd-step" style="border-bottom:none;"><div class="fd-step-num fd-step-y">3</div><div class="fd-step-body"><div class="fd-step-title" style="color:#ffe599;">Map 中剩余的旧节点 → 全部删除</div><div class="fd-step-desc">遍历结束后，Map 中未被匹配的节点都是已删除的节点，打上 Deletion 标记</div></div></div></div></div></div><div style="font-size:11px;font-weight:700;color:#a8b0cc;margin-bottom:8px;">具体场景图示：</div><div style="display:flex;flex-direction:column;gap:14px;"><div style="padding:12px 14px;background:#191c2a;border-radius:8px;border:1px solid #2e3347;"><div style="font-size:11px;color:#7eb3ff;font-weight:700;margin-bottom:6px;">场景 A：顺序未变，仅 props 更新（第一轮全部命中）</div><div style="font-size:10px;color:#8b90a8;margin-bottom:5px;">旧列表：</div><div class="fd-list"><div class="fd-li fd-li-c">A<div class="fd-li-label">key=&quot;a&quot;</div></div><div class="fd-li fd-li-c">B<div class="fd-li-label">key=&quot;b&quot;</div></div><div class="fd-li fd-li-c">C<div class="fd-li-label">key=&quot;c&quot;</div></div></div><div style="font-size:10px;color:#8b90a8;margin:5px 0;">新列表：</div><div class="fd-list"><div class="fd-li fd-li-n">A&#39;<div class="fd-li-label">key=&quot;a&quot; 复用</div></div><div class="fd-li fd-li-n">B&#39;<div class="fd-li-label">key=&quot;b&quot; 复用</div></div><div class="fd-li fd-li-n">C&#39;<div class="fd-li-label">key=&quot;c&quot; 复用</div></div></div><div style="font-size:10px;color:#6ef5a8;margin-top:5px;">✅ 三个节点全部复用，无移动，仅更新 props</div></div><div style="padding:12px 14px;background:#191c2a;border-radius:8px;border:1px solid #2e3347;"><div style="font-size:11px;color:#ffe599;font-weight:700;margin-bottom:6px;">场景 B：列表末尾新增节点（第一轮命中旧节点，第二轮处理新增）</div><div style="font-size:10px;color:#8b90a8;margin-bottom:5px;">旧列表：</div><div class="fd-list"><div class="fd-li fd-li-c">A<div class="fd-li-label">key=&quot;a&quot;</div></div><div class="fd-li fd-li-c">B<div class="fd-li-label">key=&quot;b&quot;</div></div></div><div style="font-size:10px;color:#8b90a8;margin:5px 0;">新列表：</div><div class="fd-list"><div class="fd-li fd-li-n">A&#39;<div class="fd-li-label">key=&quot;a&quot; 复用</div></div><div class="fd-li fd-li-n">B&#39;<div class="fd-li-label">key=&quot;b&quot; 复用</div></div><div class="fd-li fd-li-d">C<div class="fd-li-label">key=&quot;c&quot; 新建</div></div></div><div style="font-size:10px;color:#ffe599;margin-top:5px;">🆕 C 在旧 Map 中找不到，标记 Placement（插入）</div></div><div style="padding:12px 14px;background:#191c2a;border-radius:8px;border:1px solid #2e3347;"><div style="font-size:11px;color:#d4a8ff;font-weight:700;margin-bottom:6px;">场景 C：节点移动（最复杂，第二轮处理）</div><div style="font-size:10px;color:#8b90a8;margin-bottom:5px;">旧列表：</div><div class="fd-list"><div class="fd-li fd-li-c">A<div class="fd-li-label">index=0</div></div><div class="fd-li fd-li-c">B<div class="fd-li-label">index=1</div></div><div class="fd-li fd-li-c">C<div class="fd-li-label">index=2</div></div><div class="fd-li fd-li-c">D<div class="fd-li-label">index=3</div></div></div><div style="font-size:10px;color:#8b90a8;margin:5px 0;">新列表：</div><div class="fd-list"><div class="fd-li fd-li-n">D<div class="fd-li-label">旧 index=3</div></div><div class="fd-li fd-li-n">A<div class="fd-li-label">旧 index=0</div></div><div class="fd-li fd-li-n">B<div class="fd-li-label">旧 index=1</div></div><div class="fd-li fd-li-n">C<div class="fd-li-label">旧 index=2</div></div></div><div style="font-size:10px;color:#d4a8ff;margin-top:5px;">🔍 lastPlacedIndex 算法：React 追踪&quot;最后一个可不移动的旧节点索引&quot;。D(3)→A(0)→B(1)→C(2)，A/B/C 的旧索引均小于 lastPlacedIndex(3)，被标记为 Placement（移动到后面）。</div></div></div><div class="fd-note fd-np" style="margin-top:12px;">💡 <strong>lastPlacedIndex 核心思想</strong>：React 优先保持相对顺序不变的节点不动，对于在旧位置&quot;靠前&quot;却在新位置&quot;靠后&quot;的节点，打上移动标记。这样可以最小化真实 DOM 操作次数。</div></div></div><hr><h2 id="六、key-的本质作用" tabindex="-1">六、key 的本质作用 <a class="header-anchor" href="#六、key-的本质作用" aria-label="Permalink to &quot;六、key 的本质作用&quot;">​</a></h2><p><code>key</code> 是 React Diff 算法在处理<strong>列表节点</strong>时，用来识别&quot;逻辑上相同的节点&quot;的唯一标识。它的本质是：<strong>让 Diff 算法在 O(n) 时间内，跨越索引位置找到可复用节点。</strong></p><div class="fd"><div class="fd-card"><div class="fd-title">📊 图解六：有 key vs 无 key 的 Diff 差异</div><div class="fd-krow"><div class="fd-kcol fd-kcol-bad"><div style="font-size:12px;font-weight:700;color:#ff8f8f;margin-bottom:10px;">❌ 无 key（或用 index 作 key）</div><div class="fd-phase-tag fd-pt-old">旧列表</div><div class="fd-list" style="margin-bottom:8px;"><div class="fd-li fd-li-c">Alice<div class="fd-li-label">i=0</div></div><div class="fd-li fd-li-c">Bob<div class="fd-li-label">i=1</div></div><div class="fd-li fd-li-c">Carol<div class="fd-li-label">i=2</div></div></div><div class="fd-phase-tag fd-pt-new">新列表（头部插入 Dave）</div><div class="fd-list" style="margin-bottom:8px;"><div class="fd-li fd-li-d">Dave<div class="fd-li-label">i=0</div></div><div class="fd-li fd-li-d">Alice<div class="fd-li-label">i=1</div></div><div class="fd-li fd-li-d">Bob<div class="fd-li-label">i=2</div></div><div class="fd-li fd-li-d">Carol<div class="fd-li-label">i=3</div></div></div><div class="fd-note fd-nr" style="font-size:11px;">按 index 对比：<br>i=0: Alice≠Dave → 更新<br>i=1: Bob≠Alice → 更新<br>i=2: Carol≠Bob → 更新<br>i=3: null→Carol → 新建<br>结果：<strong>4 个节点全部重建/更新</strong></div></div><div class="fd-kcol fd-kcol-good"><div style="font-size:12px;font-weight:700;color:#6ef5a8;margin-bottom:10px;">✅ 有正确的 key（稳定唯一标识）</div><div class="fd-phase-tag fd-pt-old">旧列表</div><div class="fd-list" style="margin-bottom:8px;"><div class="fd-li fd-li-c">Alice<div class="fd-li-label">key=&quot;alice&quot;</div></div><div class="fd-li fd-li-c">Bob<div class="fd-li-label">key=&quot;bob&quot;</div></div><div class="fd-li fd-li-c">Carol<div class="fd-li-label">key=&quot;carol&quot;</div></div></div><div class="fd-phase-tag fd-pt-new">新列表（头部插入 Dave）</div><div class="fd-list" style="margin-bottom:8px;"><div class="fd-li fd-li-d">Dave<div class="fd-li-label">key=&quot;dave&quot; 新建</div></div><div class="fd-li fd-li-n">Alice<div class="fd-li-label">key=&quot;alice&quot; 复用</div></div><div class="fd-li fd-li-n">Bob<div class="fd-li-label">key=&quot;bob&quot; 复用</div></div><div class="fd-li fd-li-n">Carol<div class="fd-li-label">key=&quot;carol&quot; 复用</div></div></div><div class="fd-note fd-ng" style="font-size:11px;">通过 key 映射：<br>alice/bob/carol 都能找到旧节点 → 复用<br>dave 在 Map 中不存在 → 新建<br>结果：<strong>仅 1 个新建，3 个复用，状态保留</strong></div></div></div><div style="margin-top:12px;padding:12px 14px;background:#191c2a;border-radius:8px;border:1px solid #2e3347;"><div style="font-size:11px;font-weight:700;color:#ffe599;margin-bottom:6px;">⚠️ key 使用原则</div><div style="display:flex;gap:10px;flex-wrap:wrap;font-size:11px;"><div style="flex:1;min-width:180px;padding:7px 10px;border-radius:6px;background:rgba(61,220,132,.07);border:1px solid rgba(61,220,132,.2);"><div style="color:#6ef5a8;font-weight:700;margin-bottom:4px;">✅ 应该这样做</div><div style="color:#8b90a8;line-height:1.6;">使用数据的稳定唯一 ID（如数据库 ID、UUID）<br>同级兄弟节点间唯一即可（不需全局唯一）</div></div><div style="flex:1;min-width:180px;padding:7px 10px;border-radius:6px;background:rgba(255,92,92,.07);border:1px solid rgba(255,92,92,.2);"><div style="color:#ff8f8f;font-weight:700;margin-bottom:4px;">❌ 不应该这样做</div><div style="color:#8b90a8;line-height:1.6;">使用数组 index 作 key（增删时顺序变化会引发错误复用）<br>使用 Math.random() 作 key（每次渲染都变，强制全量重建）</div></div></div></div></div></div><hr><h2 id="七、首次挂载-vs-更新对比总结" tabindex="-1">七、首次挂载 vs 更新对比总结 <a class="header-anchor" href="#七、首次挂载-vs-更新对比总结" aria-label="Permalink to &quot;七、首次挂载 vs 更新对比总结&quot;">​</a></h2><div class="fd"><div class="fd-card"><div class="fd-title">📊 图解七：Mount vs Update 全流程对比</div><div class="fd-diff-row"><div class="fd-diff-col fd-diff-bad"><div class="fd-diff-hd"><span style="font-size:14px;">🌱</span> <span style="color:#6ef5a8;">首次挂载（Mount）</span></div><div class="fd-diff-item"><strong>触发来源</strong>：<code>ReactDOM.createRoot().render(&lt;App/&gt;)</code></div><div class="fd-diff-item"><strong>current 树</strong>：不存在（为 null）</div><div class="fd-diff-item"><strong>Diff 操作</strong>：无对比，直接调用 <code>createFiberFromElement</code> 全量创建</div><div class="fd-diff-item"><strong>flags 标记</strong>：所有节点都打上 <code>Placement</code>（需要插入 DOM）</div><div class="fd-diff-item"><strong>effectList</strong>：包含整棵树的所有节点</div><div class="fd-diff-item"><strong>Commit 操作</strong>：一次性将整棵 Fiber 树对应的 DOM 插入页面</div><div class="fd-diff-item"><strong>生命周期</strong>：触发 <code>componentDidMount</code> / <code>useEffect</code>（首次）</div></div><div class="fd-diff-col" style="background:#1b1e2c;"><div class="fd-diff-hd"><span style="font-size:14px;">🔄</span> <span style="color:#7eb3ff;">状态更新（Update）</span></div><div class="fd-diff-item"><strong>触发来源</strong>：<code>setState</code> / <code>dispatch</code> / 父组件重渲染</div><div class="fd-diff-item"><strong>current 树</strong>：存在，提供对比基准</div><div class="fd-diff-item"><strong>Diff 操作</strong>：<code>reconcileChildFibers</code> 对比新 Element 与旧 Fiber，决定复用或新建</div><div class="fd-diff-item"><strong>flags 标记</strong>：仅标记实际变化的节点（Update / Placement / Deletion）</div><div class="fd-diff-item"><strong>effectList</strong>：只包含有 flags 的节点（通常远少于全量）</div><div class="fd-diff-item"><strong>Commit 操作</strong>：按 effectList 最小化 DOM 操作</div><div class="fd-diff-item"><strong>生命周期</strong>：触发 <code>componentDidUpdate</code> / <code>useEffect</code>（cleanup + 重新执行）</div></div></div><div style="margin-top:12px;padding:12px 14px;background:#191c2a;border-radius:8px;border:1px solid #2e3347;"><div style="font-size:11px;font-weight:700;color:#a8b0cc;margin-bottom:8px;">🏗️ 两阶段 Fiber 创建函数对比</div><div style="display:flex;gap:10px;flex-wrap:wrap;font-size:11px;font-family:monospace;"><div style="flex:1;min-width:220px;padding:8px 12px;border-radius:7px;background:rgba(61,220,132,.07);border:1px solid rgba(61,220,132,.2);"><div style="color:#6ef5a8;font-weight:700;margin-bottom:4px;font-family:sans-serif;">首次挂载</div><div style="color:#8b90a8;">mountChildFibers()</div><div style="color:#6ef5a8;">→ createFiberFromElement()</div><div style="color:#8b90a8;margin-top:4px;font-family:sans-serif;font-size:10px;">不追踪副作用（根节点除外），减少不必要的标记开销</div></div><div style="flex:1;min-width:220px;padding:8px 12px;border-radius:7px;background:rgba(79,142,247,.07);border:1px solid rgba(79,142,247,.2);"><div style="color:#7eb3ff;font-weight:700;margin-bottom:4px;font-family:sans-serif;">状态更新</div><div style="color:#8b90a8;">reconcileChildFibers()</div><div style="color:#7eb3ff;">→ useFiber() 或 createFiberFromElement()</div><div style="color:#8b90a8;margin-top:4px;font-family:sans-serif;font-size:10px;">追踪副作用，为变化的节点打上 flags 标记</div></div></div></div><div class="fd-note fd-nb" style="margin-top:10px;">💡 这两个函数是同一套逻辑（<code>ChildReconciler</code>）用不同参数（<code>shouldTrackSideEffects</code>）创建的两个版本，这也是 React 源码中经典的&quot;闭包工厂&quot;模式。</div></div></div><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">问题</th><th style="text-align:left;">答案</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Fiber 和 React Element 的关系？</strong></td><td style="text-align:left;">Element 是每次渲染临时生成的&quot;蓝图&quot;（不可变），Fiber 是持久的&quot;建筑实体&quot;，Reconciliation 就是用新蓝图更新建筑的过程。</td></tr><tr><td style="text-align:left;"><strong>双缓冲的意义？</strong></td><td style="text-align:left;">current 树服务当前屏幕，WIP 树在后台构建，互不干扰，Commit 阶段原子切换，避免用户看到中间态。</td></tr><tr><td style="text-align:left;"><strong>单节点 Diff 的核心？</strong></td><td style="text-align:left;">key 优先匹配，type 作为复用的最终判断；key 相同 type 不同时，全量重建，不保留状态。</td></tr><tr><td style="text-align:left;"><strong>多节点 Diff 的两轮含义？</strong></td><td style="text-align:left;">第一轮处理顺序不变的主流情况（贪心），第二轮用 Map 处理乱序移动/新增/删除。</td></tr><tr><td style="text-align:left;"><strong>为什么不能用 index 作 key？</strong></td><td style="text-align:left;">增删时 index 变化会导致错误复用（旧节点被当成不同节点的 key 映射），引发 UI 错乱和状态丢失。</td></tr><tr><td style="text-align:left;"><strong>Mount 和 Update 的本质区别？</strong></td><td style="text-align:left;">Mount 时 current 树为 null，全量创建；Update 时有旧 Fiber 可对比，最小化变更。</td></tr></tbody></table>',41)])])}const b=i(l,[["render",a]]);export{p as __pageData,b as default};
